import React, { useState } from 'react';
import { Link } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import toast from 'react-hot-toast';

export default function Login() {
  const { login } = useAuth();
  const [form, setForm] = useState({ email: '', password: '' });
  const [loading, setLoading] = useState(false);

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    try {
      await login(form);
      toast.success('Welcome back!');
    } catch (err) {
      toast.error(err.response?.data?.message || 'Login failed');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div style={{
      minHeight: '100vh',
      display: 'flex',
      alignItems: 'center',
      justifyContent: 'center',
      background: 'linear-gradient(135deg, #e0f7ec, #f8fafc)',
      padding: 30
    }}>
      <div style={{ width: '100%', maxWidth: 500 }}>

        {/* HEADER */}
        <div style={{ textAlign: 'center', marginBottom: 40 }}>
          <h1 style={{
            fontSize: 44,
            fontWeight: '800',
            background: 'linear-gradient(90deg, #16a34a, #22c55e)',
            WebkitBackgroundClip: 'text',
            WebkitTextFillColor: 'transparent',
            marginBottom: 10
          }}>
            ⚡ TeamTask
          </h1>

          <p style={{
            color: '#64748b',
            fontSize: 16
          }}>
            Smart Team Management Platform
          </p>
        </div>

        {/* CARD */}
        <div style={{
          background: '#ffffff',
          padding: 40,
          borderRadius: 20,
          boxShadow: '0 20px 60px rgba(0,0,0,0.08)',
          border: '1px solid #e2e8f0'
        }}>

          <h2 style={{
            textAlign: 'center',
            marginBottom: 25,
            fontSize: 26,
            fontWeight: '700',
            color: '#111827'
          }}>
            Welcome Back 👋
          </h2>

          <form onSubmit={handleSubmit}>

            {/* EMAIL */}
            <div style={{ marginBottom: 20 }}>
              <label style={{ fontSize: 15, fontWeight: 600 }}>Email</label>
              <input
                type="email"
                placeholder="you@example.com"
                value={form.email}
                onChange={e => setForm({ ...form, email: e.target.value })}
                required
                style={{
                  width: '100%',
                  padding: '14px 16px',
                  marginTop: 8,
                  borderRadius: 12,
                  border: '1px solid #cbd5e1',
                  fontSize: 15,
                  outline: 'none'
                }}
              />
            </div>

            {/* PASSWORD */}
            <div style={{ marginBottom: 25 }}>
              <label style={{ fontSize: 15, fontWeight: 600 }}>Password</label>
              <input
                type="password"
                placeholder="••••••••"
                value={form.password}
                onChange={e => setForm({ ...form, password: e.target.value })}
                required
                style={{
                  width: '100%',
                  padding: '14px 16px',
                  marginTop: 8,
                  borderRadius: 12,
                  border: '1px solid #cbd5e1',
                  fontSize: 15,
                  outline: 'none'
                }}
              />
            </div>

            {/* BUTTON */}
            <button
              type="submit"
              disabled={loading}
              style={{
                width: '100%',
                padding: '14px',
                borderRadius: 12,
                border: 'none',
                background: 'linear-gradient(90deg, #16a34a, #22c55e)',
                color: '#fff',
                fontSize: 16,
                fontWeight: '700',
                cursor: 'pointer',
                transition: '0.3s'
              }}
            >
              {loading ? 'Signing in...' : 'Sign In →'}
            </button>

          </form>

          {/* FOOTER */}
          <p style={{
            textAlign: 'center',
            marginTop: 20,
            fontSize: 14,
            color: '#64748b'
          }}>
            No account? <Link to="/register" style={{ color: '#16a34a', fontWeight: 600 }}>Register here</Link>
          </p>

        </div>

        {/* INFO BOX */}
        <div style={{
          marginTop: 25,
          padding: 18,
          background: '#ecfdf5',
          borderRadius: 12,
          border: '1px solid #bbf7d0'
        }}>
          <p style={{ fontSize: 13, color: '#065f46', marginBottom: 5 }}>
            💡 Demo Accounts:
          </p>
          <p style={{ fontSize: 13, color: '#065f46' }}>
            Register as <strong>admin</strong> to create projects & tasks
          </p>
          <p style={{ fontSize: 13, color: '#065f46' }}>
            Register as <strong>member</strong> to view & submit tasks
          </p>
        </div>

      </div>
    </div>
  );
}
